# Get all FUNC symbols from the debug file for the two unresolved addresses
aarch64-linux-gnu-readelf -Ws /tmp/mono_symbols/libmonosgen-2.0.so.dbg | awk '$4 == "FUNC" && $2 != "0000000000000000" {print $2, $3, $8}' | sort > /tmp/all_syms.txt

python3 -c "
syms = []
with open('/tmp/all_syms.txt') as f:
    for line in f:
        parts = line.strip().split()
        if len(parts) >= 3:
            addr = int(parts[0], 16)
            size = int(parts[1])
            name = parts[2]
            syms.append((addr, size, name))
syms.sort()

for pc in [0x2f4b20, 0x2f4c84]:
    for addr, size, name in syms:
        if addr <= pc < addr + size:
            print(f'0x{pc:08x}: {name}+0x{pc-addr:x} (at 0x{addr:x}, size={size})')
            break
    else:
        # nearest
        best = None
        for addr, size, name in syms:
            if addr <= pc:
                best = (addr, size, name)
        if best:
            print(f'0x{pc:08x}: nearest {best[2]}+0x{pc-best[0]:x} (size={best[1]})')
        else:
            print(f'0x{pc:08x}: ???')
"

