syms = []
for line in sys.stdin:
    parts = line.strip().split()
    if len(parts) >= 4:
        try:
            addr = int(parts[0], 16)
            size = int(parts[1])
            syms.append((addr, size, parts[2], parts[3]))
        except:
            pass
syms.sort()
for pc in [0x2f4b20, 0x2f4c84]:
    # Find containing symbol
    found = False
    for addr, size, typ, name in syms:
        if size > 0 and addr <= pc < addr + size:
            print(f'0x{pc:08x}: {name} (type={typ}, base=0x{addr:x}, +0x{pc-addr:x})')
            found = True
    if not found:
        # nearest below
        best = None
        for addr, size, typ, name in syms:
            if addr <= pc:
                best = (addr, size, typ, name)
        if best:
            print(f'0x{pc:08x}: nearest={best[3]} at 0x{best[0]:x} size={best[1]} type={best[2]} offset=+0x{pc-best[0]:x}')
" 2>&1 | head -10

